// Universal Lead Normalizer
// Handles leads from all sources

const input = $input.first().json;
const body = input.body || input;

// Detect source
const source = body.source || 
               body.lead_source || 
               body.form_name ||
               (body.ad_id ? 'facebook_ads' : 'website') ||
               'unknown';

// Extract lead data from any format
const lead = {
  // Identity
  id: 'LEAD_' + Date.now() + '_' + Math.random().toString(36).substr(2, 6).toUpperCase(),

  full_name: body.full_name || 
             body.name || 
             `${body.first_name || ''} ${body.last_name || ''}`.trim() || 
             'Unknown',

  email: body.email || 
         body.email_address || 
         body.contact_email || '',

  phone: body.phone || 
         body.phone_number || 
         body.mobile || 
         body.contact_phone || '',

  // Property Requirements
  property_type: body.property_type || 
                 body.propertyType || 
                 body.type || 'Not Specified',

  bedrooms: body.bedrooms || 
            body.beds || 
            body.bedroom_count || null,

  budget_min: parseFloat(body.budget_min || body.min_budget || body.price_min || 0),

  budget_max: parseFloat(body.budget_max || body.max_budget || 
              body.price_max || body.budget || 0),

  location: body.location || 
            body.preferred_location || 
            body.area || 
            body.city || 'Not Specified',

  // Intent Signals          
  buying_timeline: body.buying_timeline || 
                   body.timeline || 
                   body.when || 'Not Specified',

  financing: body.financing || 
             body.payment_method || 
             body.mortgage || 'Not Specified',

  message: body.message || 
           body.comments || 
           body.notes || 
           body.additional_info || '',

  // Tracking
  source: source,
  utm_source: body.utm_source || '',
  utm_campaign: body.utm_campaign || '',
  ad_id: body.ad_id || '',
  form_id: body.form_id || '',

  // Timestamps
  captured_at: new Date().toISOString(),
  created_date: new Date().toLocaleDateString('en-US', {
    year: 'numeric', month: 'long', day: 'numeric'
  })
};

// Basic validation flags
lead.has_email = lead.email.includes('@');
lead.has_phone = lead.phone.length > 7;
lead.has_budget = lead.budget_max > 0;
lead.has_location = lead.location !== 'Not Specified';
lead.has_timeline = lead.buying_timeline !== 'Not Specified';

// Completeness score (0-100)
const fields = [lead.has_email, lead.has_phone, lead.has_budget, 
                lead.has_location, lead.has_timeline, 
                lead.property_type !== 'Not Specified',
                lead.bedrooms !== null,
                lead.message.length > 10];
lead.data_completeness = Math.round((fields.filter(Boolean).length / fields.length) * 100);

return [{ json: lead }];

