parameters.jsCode:
const aiResponse = $input.first().json.message?.content || 
                   $input.first().json.choices?.[0]?.message?.content || '{}';
const leadData = $('Normalize & Extract Lead Data').first().json;

let qualification = {};
try {
  const cleaned = aiResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  qualification = JSON.parse(cleaned);
} catch(e) {
  qualification = {
    score: 30,
    qualification: 'LOW_PRIORITY',
    score_breakdown: {},
    buying_signals: [],
    concerns: ['Unable to parse AI response'],
    recommended_action: 'Manual review required',
    best_contact_time: 'Business hours',
    agent_notes: 'AI parsing failed - manual review needed',
    suggested_properties: leadData.property_type,
    urgency_level: 'nurture'
  };
}

// Merge lead data with qualification
const enrichedLead = {
  ...leadData,
  qualification: {
    ...qualification,
    qualified_at: new Date().toISOString()
  },
  priority: qualification.qualification,
  score: qualification.score,
  urgency: qualification.urgency_level,

  // Flags for routing
  is_high_intent: qualification.qualification === 'HIGH_INTENT',
  is_medium_interest: qualification.qualification === 'MEDIUM_INTEREST',
  is_low_priority: qualification.qualification === 'LOW_PRIORITY',

  // Priority labels
  priority_emoji: qualification.qualification === 'HIGH_INTENT' ? '🔥' :
                  qualification.qualification === 'MEDIUM_INTEREST' ? '⚡' : '❄️',
  priority_label: qualification.qualification === 'HIGH_INTENT' ? 'HOT LEAD' :
                  qualification.qualification === 'MEDIUM_INTEREST' ? 'WARM LEAD' : 'COLD LEAD'
};

return [{ json: enrichedLead }];

